const body = $json.body ?? $json;
const customers = Array.isArray(body.customers) ? body.customers : [];
const now = Date.now();
const dayMs = 24 * 60 * 60 * 1000;
const segments = customers.map((customer) => {
  const lastVisit = customer.lastVisit ? new Date(customer.lastVisit).getTime() : 0;
  const daysSinceVisit = lastVisit ? Math.floor((now - lastVisit) / dayMs) : 999;
  const visits90d = Number(customer.visits90d ?? 0);
  const spend90d = Number(customer.spend90d ?? 0);
  let segment = 'standard';
  let offer = 'thank_you_next_visit';
  if (daysSinceVisit >= 45) {
    segment = 'winback';
    offer = 'limited_time_return_offer';
  } else if (visits90d >= 8 || spend90d >= 250) {
    segment = 'vip';
    offer = 'exclusive_bonus_item';
  } else if (daysSinceVisit >= 21) {
    segment = 'at_risk';
    offer = 'small_discount_or_bonus_side';
  }
  return {
    customerId: customer.customerId ?? customer.email ?? customer.phone,
    name: customer.name ?? 'Guest',
    channel: customer.preferredChannel ?? 'email',
    daysSinceVisit,
    visits90d,
    spend90d,
    segment,
    recommendedOffer: offer,
    messageStatus: 'draft_for_human_approval'
  };
});
return [{
  json: {
    workflow: 'qsr-loyalty-winback-segmenter',
    storeId: body.storeId ?? 'unknown',
    segmentCounts: segments.reduce((acc, item) => {
      acc[item.segment] = (acc[item.segment] ?? 0) + 1;
      return acc;
    }, {}),
    segments
  }
}];
